SELECT
id,
feature_id      AS featureId,
parameter_id    AS parameterId,
feature_layer   AS featureLayer,
dimension_index AS dimensionIndex  FROM feature_parameter


        AND id = #{id}


        AND feature_id = #{featureId}


        AND parameter_id = #{parameterId}


        AND feature_layer = #{featureLayer}


        AND dimension_index = #{dimensionIndex}
